# --- Parameters ---
t = np.linspace(-5, 5, 10000)
f = np.fft.fftfreq(len(t), d=(t[1] - t[0]))
f = np.fft.fftshift(f)

initial_width = 1.0

def rect_pulse(t, width):
    """Rectangular pulse of given width centered at 0."""
    pulse = np.where(np.abs(t) <= width / 2.0, 1.0, 0.0)
    return pulse

def compute_fft(pulse, t):
    """Compute the FFT and return shifted magnitude spectrum."""
    dt = t[1] - t[0]
    spectrum = np.fft.fft(pulse) * dt
    spectrum_shifted = np.fft.fftshift(spectrum)
    return np.abs(spectrum_shifted)

def analytical_sinc(f, width):
    """Analytical Fourier Transform of rect pulse: width * sinc(f * width)."""
    return width * np.sinc(f * width)  # np.sinc includes pi factor: sinc(x) = sin(pi*x)/(pi*x)

